async (page) => {
  // Eat burger (slot 7) to heal
  await page.evaluate((slot) => {
    window.game.menu.getInventory().selectEdible(slot);
  }, 7);
  await page.waitForTimeout(500);

  // Set attack style to Stab (index 0 for Iron Spear = Accuracy+Defense)
  await page.evaluate(() => window.game.menu.profile.attackStyleCallback(0));
  await page.waitForTimeout(500);

  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  return state;
}

async (page) => {
  // E3 is the 160HP mob at (297,115) - click it directly
  const mob = await page.evaluate(() => {
    const entities = window.__latestGameState.nearby_entities;
    const target = entities.find(e => e.type === 3 && e.hp === 160 && e.on_screen && e.click_x);
    if (!target) return null;
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: target.click_x, clientY: target.click_y, bubbles: true, ctrlKey: false }));
    return { name: target.name, x: target.x, y: target.y, click_x: target.click_x, click_y: target.click_y };
  });
  await page.waitForTimeout(7000);
  // Second click to finish it off
  await page.evaluate((label) => JSON.stringify(window.__clickEntity(label)), 'E0');
  await page.waitForTimeout(7000);
  return JSON.stringify(mob);
}
